fn Neighbor.relX(neighbor: Neighbor) i32 {
    return switch (neighbor) {
        .xPositive => 1,
        .xNegative => -1,
        else => 0,
    };
}

fn Neighbor.reverse(neighbor: Neighbor) Neighbor {
    return switch (neighbor) {
        .xPositive => .xNegative,
        .xNegative => .xPositive,
        .yPositive => .yNegative,
        .yNegative => .yPositive,
        .zPositive => .zNegative,
        .zNegative => .zPositive,
    };
}

