pub const LogData = struct {
    enabledConnections: u16,

    fn init(data: u16) LogData {
        return .{ .enabledConnections = data };
    }

    fn setConnection(self: *LogData, side: Neighbor, connected: bool) void {
        if (connected) {
            self.enabledConnections |= @as(u16, 1) << @intFromEnum(side);
        } else {
            self.enabledConnections &= ~(@as(u16, 1) << @intFromEnum(side));
        }
    }
};

pub fn getPattern(data: LogData, side: Neighbor) Pattern {
    if (data.isConnected(side)) {
        return .cut;
    }

    const pattern = branch.getPattern(data, side).?;

    switch (pattern) {
        .dot => return .dot,
        .halfLine, .line => |dir| return .{ .line = .fromBranchDirection(dir) },
        .bend => |dir| return .{ .bend = dir },
        .intersection => |dir| return .{ .intersection = dir },
        .cross => return .cross,
    }
}

