pub fn migrateBlockName(oldName: []const u8) ?[]const u8 {
    const migrations = .{
        .{ .old = "glow_crystal/dark_gray", .new = "glow_crystal/grey" },
        .{ .old = "glow_crystal/dark_green", .new = "glow_crystal/viridian" },
        // ... add all other migrations here
        .{ .old = "lush_grass_vegetation", .new = "grass/vegetation/lush" },
    };

    for (migrations) |migration| {
        if (std.mem.eql(u8, oldName, migration.old)) {
            return migration.new;
        }
    }
    return null;
}

